h2-close-flows-and-paywalls-pe3b0c442.translation:
```javascript
import React, { useCallback } from 'react';
import { AdaptyFlowView } from 'react-native-adapty';
import type { FlowEventHandlers } from 'react-native-adapty';

function MyPaywall({ flow }) {
  const onCloseButtonPress = useCallback<FlowEventHandlers['onCloseButtonPress']>(() => {
    // Handle close button press - navigate away or hide component
    navigation.goBack();
  }, [navigation]);

  return (
    <AdaptyFlowView
      flow={flow}
      style={styles.container}
      onCloseButtonPress={onCloseButtonPress}
    />
  );
}
```

h2-open-urls-from-flows-and-paywalls-pab.translation:
```javascript
import React, { useCallback } from 'react';
import { Linking } from 'react-native';
import { AdaptyFlowView } from 'react-native-adapty';
import type { FlowEventHandlers } from 'react-native-adapty';

function MyPaywall({ flow }) {
  const onUrlPress = useCallback<FlowEventHandlers['onUrlPress']>((url) => {
    Linking.openURL(url);
  }, []);

  return (
    <AdaptyFlowView
      flow={flow}
      style={styles.container}
      onUrlPress={onUrlPress}
    />
  );
}
```

